  if (!product) { res.status(404).json({ error: "Product not found" }); return; }
  const { adjustment } = req.body as { adjustment: number };
  if (typeof adjustment !== "number") { res.status(400).json({ error: "adjustment must be a number" }); return; }
  const newStock = product.stock + adjustment;
  if (newStock < 0) { res.status(400).json({ error: "Insufficient stock" }); return; }
  product.stock = newStock;
  res.json({ ...product, isLowStock: product.stock < 10, inventoryValue: Math.round(product.price * product.stock * 100) / 100 });
