  if (maxPrice && typeof maxPrice === "string") {
    const max = parseFloat(maxPrice);
    if (!isNaN(max)) filters.maxPrice = max;
  }

  const result = listProducts(filters);
  if (!result.ok) {
    res.status(result.status).json({ error: result.error });
    return;
  }
  res.json(result.data);
});

